"use client";
import { FormEvent,useEffect,useState } from "react";import type { Showcase,VendorCard } from "@wedjan/shared";import { api } from "@/lib/api";import { uploadMedia } from "@/lib/media-upload";import styles from "../../../discovery.module.css";
export default function VendorShowcases(){const [owned,setOwned]=useState<Showcase[]>([]);const [pending,setPending]=useState<Showcase[]>([]);const [tags,setTags]=useState<VendorCard[]>([]);const [busy,setBusy]=useState(false);const [message,setMessage]=useState("");const refresh=()=>Promise.all([api.GET("/api/v1/showcases/me/owned").then(r=>r.data&&setOwned(r.data.items)),api.GET("/api/v1/showcases/me/pending-tags").then(r=>r.data&&setPending(r.data.items))]);useEffect(()=>{void refresh()},[]);
  async function findVendor(value:string){if(value.length<2)return setTags([]);const {data}=await api.GET("/api/v1/search/vendors",{params:{query:{q:value}}});setTags(data?.items??[])}
  async function submit(e:FormEvent<HTMLFormElement>){e.preventDefault();setBusy(true);setMessage("");try{const fd=new FormData(e.currentTarget);const files=fd.getAll("photos").filter((x):x is File=>x instanceof File&&x.size>0);if(files.length<3)throw new Error("Choose at least 3 photos to publish.");const uploaded=[];for(const file of files)uploaded.push(await uploadMedia(file,"IMAGE"));const tagId=String(fd.get("tagVendor")??"");const {data}=await api.POST("/api/v1/showcases",{body:{title:String(fd.get("title")),eventType:String(fd.get("eventType")) as "WEDDING",eventDate:String(fd.get("eventDate"))||undefined,city:String(fd.get("city")),country:String(fd.get("country")).toUpperCase(),coverMediaId:uploaded[0].id,descriptionMd:String(fd.get("description")),styleTags:String(fd.get("styles")).split(",").map(x=>x.trim()).filter(Boolean),media:uploaded.map((x,i)=>({mediaId:x.id,sort:i})),vendorTags:tagId?[{vendorId:tagId,roleLabel:String(fd.get("roleLabel")||"Event partner")}]:[],status:"PUBLISHED"}});if(!data)throw new Error("Could not publish showcase");setMessage(`Published “${data.title}”. Tagged vendors must accept before their credit appears.`);e.currentTarget.reset();await refresh()}catch(err){setMessage(err instanceof Error?err.message:"Could not publish showcase")}finally{setBusy(false)}}
  return <><h1 className="app-page-title">Real events</h1><p className="app-page-subtitle">Publish genuine work and credit collaborators. Credits stay hidden until accepted.</p>{pending.length>0&&<section className="dashboard-card"><h2>Credits awaiting your response</h2>{pending.map(show=><div className="record-row" key={show.id}><strong>{show.title} by {show.ownerBusinessName}</strong><span>{show.vendorTags.filter(t=>t.status==="PENDING").map(tag=><span key={tag.id}><button className="ghost-button" onClick={async()=>{await api.POST("/api/v1/showcases/tags/{tagId}/accept",{params:{path:{tagId:tag.id}}});await refresh()}}>Accept</button><button className="ghost-button" onClick={async()=>{await api.POST("/api/v1/showcases/tags/{tagId}/decline",{params:{path:{tagId:tag.id}}});await refresh()}}>Decline</button></span>)}</span></div>)}</section>}<div className="dashboard-grid"><section className="dashboard-card"><h2>Add a real event</h2><form className={styles.form} onSubmit={submit}><label>Title<input className={styles.input} name="title" required/></label><label>Event type<select className={styles.select} name="eventType"><option>WEDDING</option><option>CORPORATE</option><option>BIRTHDAY</option><option>CULTURAL</option><option>OTHER</option></select></label><label>Event date<input className={styles.input} type="date" name="eventDate"/></label><label>City<input className={styles.input} name="city" required/></label><label>Country code<input className={styles.input} name="country" minLength={2} maxLength={2} required/></label><label>Description<textarea name="description"/></label><label>Style tags, comma separated<input className={styles.input} name="styles" placeholder="garden, modern, colourful"/></label><label>Photos (at least 3)<input className={styles.input} type="file" name="photos" accept="image/*" multiple required/></label><label>Find a collaborator<input className={styles.input} onChange={e=>void findVendor(e.target.value)} placeholder="Search business"/></label>{tags.length>0&&<label>Tag vendor<select className={styles.select} name="tagVendor"><option value="">No tag</option>{tags.map(v=><option key={v.vendorId} value={v.vendorId}>{v.businessName}</option>)}</select></label>}<label>Collaborator role<input className={styles.input} name="roleLabel" placeholder="Photographer"/></label><button className={styles.button} disabled={busy}>{busy?"Uploading and publishing…":"Publish real event"}</button>{message&&<p className={styles.notice}>{message}</p>}</form></section><section className="dashboard-card"><h2>Your showcases</h2>{owned.length?owned.map(x=><div className="record-row" key={x.id}><strong>{x.title}</strong><span>{x.status}</span></div>):<p>No real events published yet.</p>}</section></div></>}
